                List<string> inValues = new List<string>();
                foreach (string v in values)
                {
                    inValues.Add("'" + v.Trim() + "'");
                }
                whereConditions.Add(columnName + " IN (" + string.Join(", ", inValues) + ")");
            }
            else if (value.StartsWith(">") || value.StartsWith("<") || value.StartsWith(">=") || value.StartsWith("<="))
