                    actualValue = value.Substring(2).Trim();
                }
                else if (value.StartsWith(">"))
                {
                    op = ">";
                    actualValue = value.Substring(1).Trim();
                }
                else if (value.StartsWith("<"))
                {
                    op = "<";
                    actualValue = value.Substring(1).Trim();
                }

                if (IsNumeric(actualValue))
                {
                    whereConditions.Add(columnName + " " + op + " " + actualValue);
                }
                else
                {
                    whereConditions.Add(columnName + " " + op + " '" + actualValue + "'");
                }
            }
            else if (value.Contains("%"))
            {
                whereConditions.Add(columnName + " LIKE '" + value + "'");
            }
            else
            {
                whereConditions.Add(columnName + " = '" + value + "'");
            }
        }

        if (whereConditions.Count > 0)
        {
            queryBuilder.Append(" WHERE ");
            queryBuilder.Append(string.Join(" AND ", whereConditions));
        }

